import { SOPFullContent } from './types';

export const SOP_001_TO_010: Record<string, SOPFullContent> = {
  'SOP-001': {
    sopNumber: 'SOP-001',
    title: 'Quality Management System',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure establishes and maintains the Quality Management System (QMS) for [Company Name] in compliance with ISO 13485:2016, EU MDR 2017/745, and FDA 21 CFR Part 820 (QMSR). It defines the framework for ensuring that medical devices are consistently designed, developed, produced, and serviced to meet customer and regulatory requirements.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all departments and personnel involved in the design, development, manufacturing, distribution, and servicing of medical devices. It covers the entire product lifecycle from concept through post-market surveillance. All quality system processes are managed and tracked through the Xyreg platform.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016 – Medical devices – Quality management systems\n• EU MDR 2017/745 – Medical Device Regulation\n• FDA 21 CFR Part 820 – Quality System Regulation (QMSR)\n• ISO 14971:2019 – Application of risk management to medical devices\n• SOP-002 Document Control\n• SOP-003 Management Review\n• SOP-050 Internal Auditing\nRelated Work Instructions:\n• WI-QA-001-1 Activate QMS for new company workspace\n• WI-QA-001-2 Annual review of QMS scope and process map' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• QP – Quality Policy\n• QO – Quality Objectives' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Top Management: Establish quality policy and objectives, ensure adequacy of resources, conduct management reviews, and demonstrate commitment to regulatory compliance.\n• Quality Manager: Maintain the QMS, coordinate internal audits, manage CAPA processes, and serve as Management Representative.\n• Department Heads: Implement QMS requirements within their functional areas and ensure personnel competency.\n• All Personnel: Follow documented procedures, report nonconformities, and participate in continuous improvement activities.\n• Regulatory Affairs: Ensure QMS alignment with applicable regulatory requirements for target markets.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Quality Policy and Objectives\nTop Management defines the Quality Policy within the Xyreg Company Settings module. Quality objectives are established annually and tracked using the Xyreg Dashboard, which provides real-time metrics on document compliance, CAPA status, audit findings, and training completion.\n\n6.2 QMS Documentation Structure\nThe QMS documentation hierarchy is maintained in Xyreg\'s Document Studio:\n- Level 1: Quality Manual and Quality Policy\n- Level 2: Standard Operating Procedures (SOPs)\n- Level 3: Work Instructions, Forms, and Templates\n- Level 4: Records and Evidence\nAll documents follow the document control process defined in SOP-002, with version control, review cycles, and electronic approvals managed through Xyreg.\n\n6.3 Process Approach\n[Company Name] uses a process-based approach. Each QMS process is mapped in the Xyreg QMS Blueprint, showing process interactions, inputs/outputs, and responsible parties. The Blueprint provides a visual representation of the quality system aligned to ISO 13485 clause structure.\n\n6.4 Resource Management\nRequired resources are identified during management review and tracked through Xyreg\'s resource planning features. Personnel competency requirements are defined per role and managed via the Training Module (see SOP-004).\n\n6.5 Planning\nQuality planning for new products is initiated through the Xyreg Product Lifecycle module. Each product has a defined lifecycle with phases, required documents, and deliverables. Risk-based planning per ISO 14971 is integrated into the design process.\n\n6.6 Monitoring and Measurement\nQMS performance is monitored through:\n- Internal audits (SOP-050) scheduled and tracked in Xyreg\n- CAPA metrics and trend analysis via the Xyreg CAPA Module\n- Customer feedback and complaint data via the Complaints Module\n- Supplier performance metrics via the Supplier Management Module\n- KPIs displayed on the Xyreg Company Dashboard\n\n6.7 Continuous Improvement\nImprovement opportunities identified through audits, CAPAs, management reviews, and post-market surveillance are logged in Xyreg and tracked to closure. The platform provides trend analysis to identify systemic issues requiring preventive action.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Quality Manual\n• Quality Policy Statement\n• Quality Objectives Register\n• Management Review Minutes (SOP-003)\n• Internal Audit Reports (SOP-050)\n• CAPA Log (SOP-028)\n• Training Records (SOP-004)\n• Process Interaction Map (Xyreg QMS Blueprint)' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-002': {
    sopNumber: 'SOP-002',
    title: 'Document Control',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for creating, reviewing, approving, distributing, and managing controlled documents within the Quality Management System. It ensures that only current, approved versions of documents are available at points of use and that obsolete documents are prevented from unintended use.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all controlled documents within the QMS, including SOPs, work instructions, forms, templates, specifications, and external documents of regulatory origin. All document control activities are performed within the Xyreg Document Studio and Document Management modules.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 4.2 – Documentation requirements\n• FDA 21 CFR 820.40 – Document controls\n• EU MDR 2017/745, Article 10(8) – Documentation requirements\n• SOP-QA-001 Quality Management System\n• SOP-DE-011 Design Changes\nRelated Work Instructions:\n• WI-QA-002-1 Create a new controlled document in Document Studio\n• WI-QA-002-2 Review and approve a controlled document via Mission Control\n• WI-QA-002-3 Revise an existing controlled document and increment the version\n• WI-QA-002-4 Obsolete or supersede a controlled document\n• WI-QA-002-5 Perform the scheduled periodic review of a controlled document\n• WI-QA-002-6 Register and control an external document (standard, regulation)' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• ECO – Engineering Change Order\n• Controlled Document – Any document that is part of the QMS and subject to formal review and approval\n• Document Owner – The person responsible for the content and accuracy of a document\n• DCO – Document Change Order\n• Effective Date – The date on which a document becomes active\n• Obsolete Document – A superseded version that is no longer valid for use' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Document Author: Draft new documents or revisions, ensure technical accuracy.\n• Document Owner: Responsible for document content, initiate reviews, approve changes.\n• Quality Manager: Oversee document control system, ensure compliance, manage the Xyreg Document Studio configuration.\n• Reviewers: Review documents for accuracy, completeness, and regulatory compliance within the Xyreg review workflow.\n• All Personnel: Use only current approved versions of documents, report discrepancies.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Document Creation\nNew documents are initiated in Xyreg Document Studio by selecting the appropriate template from the Template Library. The author fills in required metadata (document number, title, document type, owner) and drafts the content using the built-in editor. Xyreg automatically assigns a document number following the company numbering convention.\n\n6.2 Document Numbering\nDocuments follow the convention: [TYPE]-[NNN] (e.g., SOP-QA-001, FORM-012, TEMP-005). Xyreg maintains the document register and prevents duplicate numbering.\n\n6.3 Review and Approval\nOnce drafted, the author submits the document for review through Xyreg\'s Review Workflow:\n1. Author clicks "Send for Review" in Document Studio\n2. Designated reviewers receive a notification in their Xyreg Mission Control\n3. Reviewers provide comments or approve within the platform\n4. After all reviewers approve, the document is routed to the final approver\n5. The approver applies electronic signature to make the document effective\n6. Xyreg records the complete approval chain with timestamps\n\n6.4 Document Distribution\nApproved documents are automatically available to authorised personnel through Xyreg. Access is controlled by role-based permissions. Personnel are notified of new or revised documents through the Xyreg notification system.\n\n6.5 Document Revision\nRevisions follow the same review and approval workflow. Xyreg maintains a complete revision history showing all changes, reviewers, and approval dates. Previous versions are automatically archived and marked as obsolete.\n\n6.6 External Documents\nExternally sourced documents (standards, regulations, customer specifications) are registered in Xyreg with metadata including source, version, and review date. The system alerts when external documents require periodic review.\n\n6.7 Document Retention\nDocuments are retained for the lifetime of the medical device plus a minimum of the period required by applicable regulations. Xyreg enforces retention policies and prevents premature deletion of controlled records.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Document Register (maintained in Xyreg)\n• Document Change Orders\n• Review and Approval Records\n• Document Distribution Records\n• Obsolete Document Archive\n• FORM-002: Document Change Request Form' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-003': {
    sopNumber: 'SOP-003',
    title: 'Management Review',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for conducting periodic management reviews to ensure the continuing suitability, adequacy, and effectiveness of the Quality Management System. Management reviews provide top management with the information necessary to make strategic decisions about quality system improvements and resource allocation.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all scheduled and ad-hoc management review meetings. It covers the preparation, conduct, and follow-up of reviews including the evaluation of QMS performance data, audit results, customer feedback, CAPA effectiveness, and regulatory changes.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 5.6 – Management review\n• FDA 21 CFR 820.20 – Management responsibility\n• SOP-001 Quality Management System\n• SOP-050 Internal Auditing\n• SOP-028 Corrective and Preventive Action\nRelated Work Instructions:\n• WI-QA-003-1 Schedule a Management Review and assemble the agenda\n• WI-QA-003-2 Capture Management Review minutes, decisions and action items' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Management Review – A formal evaluation of the QMS by top management at planned intervals\n• QMS Performance Metrics – Quantitative measures of quality system effectiveness\n• Action Item – A specific task assigned during management review with an owner and due date' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Top Management: Attend and chair management reviews, make decisions on resource allocation and QMS changes.\n• Quality Manager: Prepare management review agenda and data package, facilitate the meeting, and track action items in Xyreg.\n• Department Heads: Provide department-specific data and attend reviews as required.\n• Management Representative: Ensure management review inputs are complete and report on QMS performance.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Review Frequency\nManagement reviews are conducted at least annually, with additional reviews as needed based on significant quality events or regulatory changes. The review schedule is maintained in the Xyreg Calendar.\n\n6.2 Review Inputs\nThe Quality Manager prepares the management review data package using Xyreg\'s Dashboard and Analytics. Required inputs include:\n- Audit results and findings summary (from Xyreg Audit Module)\n- Customer feedback and complaint trends (from Xyreg Complaints Module)\n- Process performance and product conformity data\n- CAPA status and effectiveness (from Xyreg CAPA Module)\n- Follow-up actions from previous management reviews\n- Changes to regulatory requirements\n- Recommendations for improvement\n- Training compliance status (from Xyreg Training Module)\n- Supplier performance data (from Xyreg Supplier Module)\n\n6.3 Conducting the Review\nThe review follows the prepared agenda. Each input area is discussed, and decisions are documented. The Xyreg platform provides real-time dashboards that can be presented during the review meeting.\n\n6.4 Review Outputs\nOutputs from management review include decisions and actions related to:\n- Improvement of the QMS and its processes\n- Improvement of product related to customer requirements\n- Resource needs\nAll action items are logged in Xyreg with assigned owners, due dates, and priority levels.\n\n6.5 Follow-up\nAction items from management review are tracked in Xyreg\'s task management system. The Quality Manager monitors completion and reports status at subsequent reviews. Overdue items trigger automated reminders through the platform.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Management Review Agenda\n• Management Review Minutes\n• Management Review Action Items (tracked in Xyreg)\n• QMS Performance Data Package\n• FORM-003: Management Review Minutes Template' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-004': {
    sopNumber: 'SOP-004',
    title: 'Personnel and Training',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines how [Company Name] establishes, delivers, and evidences personnel competency through Xyreg\'s Locked Workflow training engine. The Locked Workflow enforces a deterministic Read → Quiz → Sign sequence for every controlled document assigned to a role, producing 21 CFR Part 11–compliant electronic signatures bound to the exact document version trained.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all employees, contractors, and temporary staff (including consultants acting as editors) whose role assignment in Xyreg generates training records. It covers role-driven assignment, the five-phase Locked Workflow, AI-generated knowledge checks, e-signature attestation, and automatic re-training triggered by controlled document version bumps.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 6.2 / 6.2.2 – Human resources and competency\n• ISO 13485:2016, Clause 4.2.4 – Control of records\n• FDA 21 CFR 820.25 – Personnel\n• FDA 21 CFR Part 11, §11.10(j) – Electronic records and electronic signatures\n• EU MDR 2017/745, Article 10(9) – Personnel competence\n• EudraLex Volume 4, Annex 11 – Computerised systems\n• SOP-001 Quality Management System\n• SOP-002 Document Control\nRelated Work Instructions:\n• WI-QA-004-1 End-user: complete a Locked Workflow training (Read → Quiz → Sign) from Mission Control\n• WI-QA-004-2 Admin: sync the Training Library from approved SOPs and configure Locked Workflow fields\n• WI-QA-004-3 Handle quiz failure and remediation when max attempts is reached\n• WI-QA-004-4 Re-issue training automatically on controlled document version bump' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• PMS – Post-Market Surveillance\n• Locked Workflow – The enforced Read → Quiz → Sign sequence used by Xyreg for all controlled-document training\n• Phase Machine – The five-state lifecycle of a training record (not_started → reading → quiz_ready → sign_ready → completed) enforced by the Postgres trigger training_records_validate_phase()\n• Read Phase – Mandatory document review with a minimum read time and 30-second idle pause\n• Quiz Phase – AI-generated knowledge check (gemini-2.5-flash) with an 80 % pass threshold and configurable max attempts\n• Sign Phase – Re-authenticated electronic signature producing an immutable signature_hash\n• Attestation Statement – Verbatim text snapshotted into the training record at signing time\n• Re-authentication – Password (or equivalent) re-entry at signing, satisfying 21 CFR §11.200(a)(1)(ii)\n• Training Record – Row in training_records carrying phase, read_seconds, quiz_attempts, quiz_score, signature_hash, signed_at, attestation_text_snapshot, document_version_id\n• Quality Ring – Manager view in TeamCompetencyView showing per-user phase counts (●completed · ▶in-flight · ⚠quiz-failed · ⊗overdue)' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Quality Manager: Configures Locked Workflow fields per training module (requires_quiz, minimum_read_seconds, max_attempts, attestation_text); approves attestation language; monitors company-wide training compliance from Mission Control.\n• Department Managers: Monitor team competency via the Quality Ring (●/▶/⚠/⊗) in TeamCompetencyView; intervene on overdue or repeatedly failing trainees.\n• Training Coordinator: Maintains role-to-document mappings that drive assignTrainingForRole() fan-out; investigates expired records flagged by the version-bump re-issue.\n• All Personnel: Complete the full Read → Quiz → Sign sequence on assigned controlled documents within the deadline shown on Mission Control. Re-authentication at signing is mandatory; sharing credentials is prohibited.\n• HR Department: Triggers role assignment in Xyreg at onboarding, which fans out the initial Locked Workflow training set.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Role-driven Assignment\nWhen a user is granted a role in Xyreg, assignTrainingForRole() fans out one training_records row per (user × controlled document) with phase = \'not_started\'. Mission Control immediately surfaces phase-specific calls to action ("Start reading", "Take quiz", "Sign to complete") so trainees see the work on next login.\n\n6.2 Library Authoring\nThe Training Library auto-syncs from documents where name LIKE \'SOP-%\' and status ∈ {Approved, Effective, Released, In Review} via syncTrainingModulesFromApprovedSOPs(). Tier A foundation SOPs default requires_quiz = true, with minimum_read_seconds auto-computed from word count at 200 wpm. The Quality Manager may override any of the four Locked Workflow fields per module in the Training Module edit dialog.\n\n6.3 Phase Machine\nEvery training_records row transitions through five phases, validated server-side by the Postgres trigger training_records_validate_phase():\nnot_started → reading → quiz_ready → sign_ready → completed\nThe trigger rejects any client-supplied transition that skips a phase or re-enters a completed state without an explicit re-issue.\n\n6.4 Read Phase\nTrainingReader.tsx renders the controlled document and runs a foreground timer that pauses after 30 seconds of inactivity (no scroll, mouse, or keypress). The Quiz Phase only unlocks once read_seconds ≥ minimum_read_seconds.\n\n6.5 Quiz Phase\nTrainingQuizRunner.tsx requests a fresh quiz from the generate-training-quiz edge function, which calls gemini-2.5-flash grounded in the document body. Pass threshold is 80 %. Each attempt increments quiz_attempts; on reaching max_attempts the record routes to the remediation flow (see WI-QA-004-3).\n\n6.6 Sign Phase\nTrainingAttestation.tsx requires re-authentication, displays the verbatim attestation_text, and on confirmation writes signature_hash, signed_at, attestation_text_snapshot, and document_version_id. The hash binds the signature to the exact document version read — re-reading a future version requires a new signature.\n\n6.7 Re-training on Version Bump\nWhen a controlled document is re-approved at a higher version, syncTrainingModulesFromApprovedSOPs() flips outstanding training_records to phase = \'expired\' and reissueTrainingOnVersionUpdate() creates fresh not_started records for every prior completer. This satisfies ISO 13485 §4.2.4 control of records.\n\n6.8 Manager Surfacing\nTeamCompetencyView shows per-user phase counts (●completed · ▶in-flight · ⚠quiz-failed · ⊗overdue). Any quiz-failure or overdue record is also raised on the company-wide Mission Control briefing for the responsible Department Manager and Quality Manager.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: 'The training_records table is the single source of evidence for personnel competency under 21 CFR Part 11 and ISO 13485 §6.2.2. Each row carries:\n• phase – current Phase Machine state\n• read_seconds – elapsed in-focus reading time\n• quiz_attempts / quiz_score – knowledge-check evidence\n• signature_hash – immutable cryptographic signature bound to user + document version\n• signed_at – UTC timestamp of e-signature\n• attestation_text_snapshot – verbatim attestation language at the moment of signing\n• document_version_id – exact controlled document version trained against\nDerived artefacts:\n• Training Matrix – generated live from role-to-document mappings\n• Quality Ring snapshot – exportable from TeamCompetencyView\n• Mission Control briefing log – audit trail of overdue / failed events' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-005': {
    sopNumber: 'SOP-005',
    title: 'Design and Development Planning',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for planning design and development activities for medical devices. It ensures that design projects are properly planned, resourced, and controlled throughout the development lifecycle in accordance with ISO 13485 and applicable regulatory requirements.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all new product development projects and significant design changes to existing products. It covers the planning phase from project initiation through the establishment of the design and development plan, including identification of design stages, reviews, verification, and validation activities.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 7.3.1 – Design and development planning\n• FDA 21 CFR 820.30(b) – Design and development planning\n• EU MDR 2017/745, Annex II – Technical documentation\n• SOP-006 Design Inputs\n• SOP-007 Design Outputs\n• SOP-015 Risk Management\n• SOP-008 Design Review\nRelated Work Instructions:\n• WI-DE-005-1 Create a new Design & Development Plan for a project\n• WI-DE-005-2 Update the Design Plan when a phase gate is reached' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Design Plan – A document describing the design and development activities, phases, milestones, and deliverables\n• DHF – Design History File\n• Design Phase Gate – A formal review point between design stages\n• Cross-functional Team – A team comprising members from different functional areas' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Project Manager: Develop and maintain the design plan, coordinate cross-functional activities, track progress in Xyreg.\n• Design Lead: Define technical approach and design activities.\n• Quality Manager: Ensure design controls are properly planned and documented.\n• Regulatory Affairs: Identify applicable regulatory requirements for the target markets.\n• Risk Manager: Ensure risk management activities are integrated into the design plan.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Project Initiation\nNew design projects are initiated in the Xyreg Product Lifecycle module. The Project Manager creates a new product entry with:\n- Product name and description\n- Intended use and target patient population\n- Target markets and applicable regulations\n- Risk classification per target market\n- Preliminary project timeline\n\n6.2 Design and Development Plan\nThe design plan is created in Xyreg using the product lifecycle phase structure. The platform provides pre-configured phase templates aligned to ISO 13485 design control requirements:\n- Phase 1: Concept and Feasibility\n- Phase 2: Design Input Definition\n- Phase 3: Design and Development\n- Phase 4: Design Verification\n- Phase 5: Design Validation\n- Phase 6: Design Transfer\n- Phase 7: Design Release\n\nEach phase in Xyreg includes required deliverables, assigned documents, and phase gate review criteria.\n\n6.3 Resource Planning\nThe project team is defined in Xyreg with role assignments. Required competencies are verified against training records in the Training Module. Resource gaps are identified and addressed through the management review process.\n\n6.4 Design Reviews\nDesign review points are established at each phase gate. Xyreg schedules reviews automatically and notifies participants. Review requirements are defined per SOP-008.\n\n6.5 Risk Integration\nRisk management activities are planned as part of the design process. The Xyreg Risk Module is linked to the product lifecycle, ensuring risk analysis begins at design input and continues through post-market.\n\n6.6 Plan Updates\nThe design plan is a living document updated as the project progresses. Changes to the plan are documented in Xyreg with rationale. Significant changes require approval from the Project Manager and Quality Manager.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Design and Development Plan (in Xyreg Product Lifecycle)\n• Project Team Assignment\n• Phase Gate Review Schedule\n• Resource Plan\n• TEMP-005: Design Plan Template' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-006': {
    sopNumber: 'SOP-006',
    title: 'Design Inputs',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for identifying, documenting, reviewing, and approving design inputs for medical device development. Design inputs form the basis for all subsequent design activities and must be complete, unambiguous, and verifiable.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all design input activities for new products and significant design changes. It covers the capture of user needs, regulatory requirements, performance specifications, safety requirements, and applicable standards.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 7.3.3 – Design and development inputs\n• FDA 21 CFR 820.30(c) – Design input\n• IEC 62366-1 – Usability engineering\n• SOP-005 Design and Development Planning\n• SOP-015 Risk Management\n• SOP-013 General Safety and Performance Requirements\nRelated Work Instructions:\n• WI-DE-006-1 Capture a new design input requirement\n• WI-DE-006-2 Link a design input to a user need or regulatory requirement\n• WI-DE-006-3 Perform the design input review at the planning gate' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Design Input – The physical and performance requirements of a device that are used as a basis for device design\n• User Need – A statement of what the user requires from the device\n• Design Requirement – A specific, measurable requirement derived from user needs\n• GSPR – General Safety and Performance Requirements\n• Traceability Matrix – A document linking requirements to their source and verification' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Design Lead: Compile and document design inputs, ensure completeness and traceability.\n• Regulatory Affairs: Identify applicable regulatory and standards requirements.\n• Clinical/Marketing: Provide user needs and clinical requirements.\n• Risk Manager: Identify safety-related design inputs from risk analysis.\n• Quality Manager: Review design inputs for completeness and verifiability.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 User Needs Capture\nUser needs are gathered through market research, clinical input, and stakeholder interviews. Needs are documented in the Xyreg Requirements Module linked to the product. Each user need is assigned a unique identifier for traceability.\n\n6.2 Regulatory Requirements\nApplicable regulatory requirements are identified based on the target markets configured in Xyreg. The platform provides a GSPR checklist (per SOP-013) that maps regulatory requirements to design inputs. Standards requirements (e.g., IEC 60601, IEC 62304) are captured and linked.\n\n6.3 Design Input Documentation\nDesign inputs are documented in Xyreg with the following attributes:\n- Unique requirement ID\n- Requirement description (specific, measurable, verifiable)\n- Source (user need, standard, regulation, risk control)\n- Priority and criticality\n- Acceptance criteria\n- Verification method\n\n6.4 Risk-Based Inputs\nDesign inputs derived from risk analysis (per SOP-015) are linked to the corresponding risk control measures in the Xyreg Risk Module. This ensures traceability from hazard identification through design mitigation.\n\n6.5 Design Input Review\nDesign inputs are reviewed for:\n- Completeness: All identified needs and requirements are captured\n- Consistency: No conflicting requirements\n- Verifiability: Each input has measurable acceptance criteria\n- Traceability: Each input can be traced to its source\nThe review is conducted as part of the design review process (SOP-008) and documented in Xyreg.\n\n6.6 Design Input Approval\nApproved design inputs are baselined in Xyreg. Any subsequent changes follow the design change process (SOP-011) and require impact assessment and re-approval.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Design Input Document (in Xyreg Requirements Module)\n• User Needs Specification\n• Regulatory Requirements Matrix\n• Design Input Review Record\n• Requirements Traceability Matrix\n• TEMP-006: Design Input Template' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-007': {
    sopNumber: 'SOP-007',
    title: 'Design Outputs',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for documenting, reviewing, and approving design outputs. Design outputs must satisfy design input requirements and provide adequate information for purchasing, production, and servicing activities.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all design output documentation including drawings, specifications, software code, manufacturing procedures, labelling, and packaging specifications. It covers the creation, review, and approval of design outputs for new products and design changes.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 7.3.4 – Design and development outputs\n• FDA 21 CFR 820.30(d) – Design output\n• SOP-006 Design Inputs\n• SOP-009 Design Verification and Validation\n• SOP-010 Design Transfer\n• SOP-012 Design History File\nRelated Work Instructions:\n• WI-DE-007-1 Capture a new design output (specification, drawing, code)\n• WI-DE-007-2 Link a design output to its parent design input\n• WI-DE-007-3 Release a design output after review and approval' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Design Output – The results of design activities documented at each design phase and at the end of the total design effort\n• DMR – Device Master Record: The compilation of records containing the procedures and specifications for a finished device\n• Essential Design Output – A design output critical to the safety or performance of the device' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Design Lead: Produce design outputs that satisfy design inputs, ensure completeness.\n• Engineering Team: Create detailed technical specifications, drawings, and procedures.\n• Quality Manager: Verify that design outputs reference acceptance criteria and identify essential outputs.\n• Regulatory Affairs: Confirm design outputs meet regulatory requirements for target markets.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Design Output Documentation\nDesign outputs are documented and managed within the Xyreg Product Lifecycle module. Each design output is linked to the corresponding design input(s) through the Xyreg traceability matrix, ensuring complete requirements coverage.\n\n6.2 Design Output Content\nDesign outputs include but are not limited to:\n- Device specifications and drawings\n- Software requirements and architecture documents\n- Bill of Materials (managed in Xyreg BOM Module)\n- Manufacturing procedures and work instructions\n- Labelling and packaging specifications (per SOP-020)\n- Servicing and installation procedures\n- Risk analysis outputs (linked from Xyreg Risk Module)\n\n6.3 Essential Design Outputs\nDesign outputs essential for the proper functioning of the device are identified and documented in Xyreg. These include critical dimensions, material specifications, and process parameters that directly impact device safety or performance.\n\n6.4 Design Output Review\nDesign outputs are reviewed before release to ensure they:\n- Meet corresponding design input requirements\n- Contain or reference acceptance criteria\n- Identify characteristics essential for safe and proper use\n- Are suitable for production, purchasing, and servicing\nReview is conducted through Xyreg\'s document review workflow.\n\n6.5 Design Output Approval\nApproved design outputs are released through Xyreg\'s document control system and become part of the Device Master Record (DMR). The platform maintains version control and prevents use of unapproved outputs.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Design Output Documents (in Xyreg)\n• Requirements Traceability Matrix\n• Device Master Record\n• Design Output Review Records\n• Bill of Materials (Xyreg BOM Module)\n• TEMP-007: Design Output Specification Template' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-008': {
    sopNumber: 'SOP-008',
    title: 'Design Review',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for conducting systematic design reviews at appropriate stages of the design and development process. Design reviews evaluate the ability of design results to meet requirements and identify problems and propose necessary actions.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all formal design reviews conducted during the product development lifecycle, including phase gate reviews and ad-hoc technical reviews. It covers planning, conducting, documenting, and following up on design reviews.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 7.3.5 – Design and development review\n• FDA 21 CFR 820.30(e) – Design review\n• SOP-005 Design and Development Planning\n• SOP-006 Design Inputs\n• SOP-007 Design Outputs\n• SOP-015 Risk Management\nRelated Work Instructions:\n• WI-DE-008-1 Schedule a formal design review and assemble participants\n• WI-DE-008-2 Capture design review minutes, action items and decisions' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Design Review – A formal, documented, comprehensive, and systematic examination of a design to evaluate its capability to fulfil requirements\n• Phase Gate Review – A design review conducted at the boundary between design phases\n• Independent Reviewer – A person not directly responsible for the design stage being reviewed' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Project Manager: Schedule design reviews, prepare review packages, ensure follow-up on action items.\n• Design Review Chair: Lead the review meeting, ensure all agenda items are addressed.\n• Review Participants: Representatives from relevant functions (engineering, quality, regulatory, manufacturing, clinical).\n• Independent Reviewer(s): Provide objective assessment of the design without direct involvement.\n• Quality Manager: Ensure design review requirements are met and records are maintained in Xyreg.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Design Review Planning\nDesign reviews are planned as part of the design and development plan in Xyreg\'s Product Lifecycle module. Each phase gate has predefined review criteria and required participants. The Project Manager schedules reviews through Xyreg, which sends notifications to all participants.\n\n6.2 Review Preparation\nPrior to the review, the Project Manager prepares a review package in Xyreg containing:\n- Design review agenda\n- Design inputs and outputs for the phase under review\n- Risk analysis status from the Xyreg Risk Module\n- Verification/validation results (if applicable)\n- Open issues and action items from previous reviews\n- Outstanding design changes\n\n6.3 Conducting the Review\nThe review is conducted with participation from all required functions. The review evaluates:\n- Adequacy of design outputs against design inputs\n- Risk acceptability per the risk management plan\n- Regulatory compliance for target markets\n- Manufacturability and producibility\n- Identification of any problems or gaps\n\n6.4 Review Documentation\nDesign review minutes are documented in Xyreg, capturing:\n- Date, participants, and their functions\n- Items reviewed and decisions made\n- Action items with owners and due dates\n- Phase gate decision (proceed, proceed with conditions, or hold)\nAll participants confirm their attendance and agreement through Xyreg.\n\n6.5 Action Item Follow-up\nAction items from design reviews are tracked in Xyreg\'s task management system. The Project Manager monitors completion and ensures all actions are resolved before proceeding to the next phase gate.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Design Review Minutes (in Xyreg)\n• Design Review Agenda\n• Design Review Action Items\n• Phase Gate Decision Record\n• Attendee List\n• FORM-008: Design Review Minutes Template' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-009': {
    sopNumber: 'SOP-009',
    title: 'Design Verification and Validation',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for performing design verification and design validation activities to ensure that design outputs meet design input requirements and that the finished device conforms to defined user needs and intended uses.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all verification and validation activities for new medical device designs and significant design changes. Verification confirms that design outputs meet design input specifications. Validation confirms that the device meets user needs under actual or simulated use conditions.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clauses 7.3.6, 7.3.7 – Design verification and validation\n• FDA 21 CFR 820.30(f),(g) – Design verification and validation\n• IEC 62366-1 – Usability engineering\n• SOP-006 Design Inputs\n• SOP-007 Design Outputs\n• SOP-018 Process Validation\nRelated Work Instructions:\n• WI-DE-009-1 Define a verification or validation test case\n• WI-DE-009-2 Execute a V&V test and record the result\n• WI-DE-009-3 Log a defect found during V&V and route it to engineering\n• WI-DE-009-4 Re-test after a defect fix and update the test record\n• WI-DE-009-5 Approve the V&V report at the V&V gate' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DMR – Device Master Record\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Design Verification – Confirmation by examination and provision of objective evidence that specified requirements have been fulfilled\n• Design Validation – Confirmation by examination and provision of objective evidence that the particular requirements for a specific intended use can be consistently fulfilled\n• V&V – Verification and Validation\n• Test Protocol – A document specifying the objectives, methods, acceptance criteria, and procedures for a test' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Design Lead: Define verification and validation strategy, develop test protocols.\n• Test Engineers: Execute test protocols, document results.\n• Quality Manager: Review and approve V&V protocols and reports.\n• Regulatory Affairs: Ensure V&V activities meet regulatory expectations.\n• Clinical Affairs: Support clinical validation activities as required.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 V&V Planning\nVerification and validation activities are planned as part of the design plan in Xyreg\'s Product Lifecycle module. The V&V plan identifies:\n- Which design inputs require verification\n- Which user needs require validation\n- Test methods and acceptance criteria\n- Required test samples and conditions\n- Responsible parties and timeline\n\n6.2 Design Verification\nVerification activities confirm that each design output meets its corresponding design input. Common methods include:\n- Inspection and measurement\n- Analysis and simulation\n- Testing against specifications\n- Comparison to predicate or reference devices\nVerification protocols and results are documented in Xyreg and linked to the requirements traceability matrix.\n\n6.3 Design Validation\nValidation is performed on representative production units under actual or simulated use conditions. Validation activities include:\n- Performance testing\n- Usability evaluation (per IEC 62366-1 / SOP-026)\n- Biocompatibility testing (per SOP-040)\n- Software validation (per SOP-029)\n- Clinical evaluation (per SOP-014)\nValidation protocols and reports are managed in Xyreg\'s Document Studio.\n\n6.4 Test Protocol and Report\nEach V&V activity requires:\n- Approved test protocol (reviewed before execution)\n- Documented test results\n- Pass/fail determination against acceptance criteria\n- Summary report with conclusions\nAll documents are stored in the DHF within Xyreg.\n\n6.5 Failed Tests and Deviations\nIf verification or validation activities fail:\n- The failure is documented with root cause analysis\n- Design modifications are made as needed (per SOP-011)\n- Retesting is performed after modifications\n- The impact on risk analysis is evaluated in the Xyreg Risk Module' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• V&V Plan\n• Verification Protocols and Reports\n• Validation Protocols and Reports\n• Requirements Traceability Matrix\n• Test Data and Results\n• TEMP-009: V&V Protocol Template\n• TEMP-009a: V&V Summary Report Template' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },

  'SOP-010': {
    sopNumber: 'SOP-010',
    title: 'Design Transfer',
    sections: [
      { id: 'purpose', title: '1.0 Purpose', content: 'This procedure defines the process for transferring a verified and validated design to production. Design transfer ensures that the device design is correctly translated into production specifications, and that manufacturing processes can consistently produce a device that meets its design specifications.' },
      { id: 'scope', title: '2.0 Scope', content: 'This SOP applies to all design transfer activities from development to manufacturing for new products and significant design changes. It covers the creation of the Device Master Record (DMR), process validation, and production readiness assessment.' },
      { id: 'references', title: '3.0 References', content: '• ISO 13485:2016, Clause 7.3.8 – Design and development transfer\n• FDA 21 CFR 820.30(h) – Design transfer\n• SOP-009 Design Verification and Validation\n• SOP-018 Process Validation\n• SOP-017 Production and Service Provision\n• SOP-012 Design History File' },
      { id: 'definitions', title: '4.0 Definitions & Abbreviations', content: '• SOP – Standard Operating Procedure\n• WI – Work Instruction\n• QMS – Quality Management System\n• CAPA – Corrective and Preventive Action\n• DHF – Design History File\n• DHR – Device History Record\n• PMS – Post-Market Surveillance\n• DCO – Document Change Order\n• ECO – Engineering Change Order\n• Design Transfer – The process of translating the device design into production specifications and ensuring manufacturing readiness\n• DMR – Device Master Record: Complete set of records containing procedures and specifications for a finished device\n• Production Readiness Review – Formal assessment confirming manufacturing capability to produce the device' },
      { id: 'responsibilities', title: '5.0 Responsibilities', content: '• Project Manager: Coordinate design transfer activities and production readiness review.\n• Design Lead: Ensure design outputs are complete and suitable for manufacturing.\n• Manufacturing Engineering: Develop production processes, tooling, and work instructions.\n• Quality Manager: Verify DMR completeness, approve transfer to production.\n• Supply Chain: Ensure supplier agreements and material availability.' },
      { id: 'procedure', title: '6.0 Procedure', content: '6.1 Design Transfer Planning\nThe design transfer plan is created in Xyreg\'s Product Lifecycle module as part of the design transfer phase. The plan identifies all activities required to transition from development to production, including:\n- DMR document list and status\n- Process validation requirements\n- Equipment and tooling needs\n- Training requirements for production personnel\n- Supplier qualification status\n\n6.2 Device Master Record\nThe DMR is assembled in Xyreg and includes:\n- Device specifications and drawings\n- Bill of Materials (from Xyreg BOM Module)\n- Manufacturing procedures and work instructions\n- Quality control procedures and acceptance criteria\n- Labelling and packaging specifications\n- Installation and servicing procedures\nXyreg tracks DMR completeness and highlights missing documents.\n\n6.3 Process Validation\nManufacturing processes are validated per SOP-018 before production begins. Process validation protocols and reports are linked to the product in Xyreg. Special processes (sterilisation, welding, etc.) require completed validation before design transfer approval.\n\n6.4 Production Readiness Review\nA formal production readiness review is conducted through Xyreg with the cross-functional team. The review verifies:\n- All DMR documents are approved and released\n- Process validations are complete and acceptable\n- Production personnel are trained (verified in Xyreg Training Module)\n- Raw materials and components are available\n- Quality control procedures are in place\n- Supplier agreements are executed\n\n6.5 Design Transfer Approval\nUpon successful completion of the production readiness review, the design is formally transferred to production. The phase gate is closed in Xyreg with electronic approvals from the Project Manager, Quality Manager, and Manufacturing Manager.' },
      { id: 'records', title: '7.0 Records & Associated Documents', content: '• Design Transfer Plan\n• Device Master Record (DMR)\n• Production Readiness Review Checklist\n• Process Validation Reports\n• Training Completion Records\n• FORM-010: Production Readiness Checklist' },
      { id: 'revision-history', title: '8.0 Revision History', content: '| Version | Date | Description | Author |\n|---------|------|-------------|--------|\n| 1.0 | [Effective Date] | Initial release | Quality Manager |' },
    ],
  },
};
